import React, { useState } from 'react';
import MenuLateral from '../components/MenuLateral';

const campos = [
  { name: 'ANO', label: 'Ano', required: true, type: 'select', options: ['2024', '2025', '2026'] },
  { name: 'CAMPO2', label: 'Campo 2', required: true },
  { name: 'CAMPO3', label: 'Campo 3', required: true },
  { name: 'CAMPO4', label: 'Campo 4', required: true },
  { name: 'CAMPO5', label: 'Campo 5', required: true },
  { name: 'CAMPO6', label: 'Campo 6', required: true },
  { name: 'CAMPO7', label: 'Campo 7', required: true },
];

const CadastroTVpAPage = () => {
  const [form, setForm] = useState({});
  const handleChange = e => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };
  const handleSubmit = e => {
    e.preventDefault();
    alert('Dados salvos!');
    setForm({});
  };
  return (
    <div style={{display:'flex'}}>
      <MenuLateral />
      <div style={{marginLeft:200, flex:1, maxWidth:500, margin:'2rem auto'}}>
        <h2>Novo Relatório TVpA</h2>
        <form onSubmit={handleSubmit} style={{display:'flex',flexDirection:'column',gap:12}}>
          {campos.map(campo => (
            <div key={campo.name} style={{display:'flex',flexDirection:'column'}}>
              <label htmlFor={campo.name} style={{fontWeight:600}}>{campo.label}:</label>
              {campo.type === 'select' ? (
                <select
                  id={campo.name}
                  name={campo.name}
                  value={form[campo.name] || ''}
                  onChange={handleChange}
                  required={campo.required}
                  style={{padding:8,borderRadius:4,border:'1px solid #ccc'}}
                >
                  <option value="">Selecione o ano</option>
                  {campo.options.map(opt => (
                    <option key={opt} value={opt}>{opt}</option>
                  ))}
                </select>
              ) : (
                <input
                  id={campo.name}
                  name={campo.name}
                  value={form[campo.name] || ''}
                  onChange={handleChange}
                  required={campo.required}
                  style={{padding:8,borderRadius:4,border:'1px solid #ccc'}}
                />
              )}
            </div>
          ))}
          <button type="submit" style={{marginTop:16,background:'#1976d2',color:'#fff',border:'none',borderRadius:4,padding:'0.7rem 2rem',fontWeight:'bold',fontSize:16,cursor:'pointer'}}>Salvar</button>
        </form>
      </div>
    </div>
  );
};

export default CadastroTVpAPage;
